import { Router } from 'express';
import { answerProductQuestion, bulkAdjustProductPrices, createCategory, createProduct, deleteCategory, deleteProduct, importProductsCsv, listCategories, listProductQuestions, listProductVersions, listReviews, listAdminProducts, moderateReview, permanentlyDeleteCategory, permanentlyDeleteProduct, replyToReview, restoreProductVersion, uploadCategoryImageAsset, uploadProductImageAssets, updateCategory, updateProduct } from '../../controllers/admin/index.js';
import { createBrand, deleteBrand, getAdminBrand, listAdminBrands, updateBrand, uploadBrandLogoAsset } from '../../controllers/brandController.js';
import { restrictToPermission } from '../../middleware/permissions.js';
import { adminActionRateLimiter, uploadRateLimiter } from '../../middleware/rateLimiter.js';
import { uploadBrandLogo, uploadCategoryImage, uploadCsv, uploadProductImages } from '../../middleware/upload.js';
import { validateBody, validateParams, validateQuery } from '../../middleware/validate.js';
import { adminProductListQuerySchema, adminProductQuestionAnswerSchema, adminProductQuestionQuerySchema, brandListQuerySchema, brandSchema, bulkProductPriceAdjustSchema, categorySchema, idParamsSchema, productVersionParamsSchema, productVersionsQuerySchema, reviewModerationSchema, reviewReplySchema } from '../../validators/adminValidators.js';
import { brandIdParamsSchema } from '../../validators/brandValidators.js';
import { createProductSchema, updateProductSchema } from '../../validators/productValidators.js';
const router = Router();
router.get('/products', restrictToPermission('product:read'), validateQuery(adminProductListQuerySchema), listAdminProducts);
router.post('/products', restrictToPermission('product:write'), adminActionRateLimiter, validateBody(createProductSchema), createProduct);
router.post('/products/images', restrictToPermission('product:write'), uploadRateLimiter, uploadProductImages, uploadProductImageAssets);
router.post('/products/import', restrictToPermission('product:write'), adminActionRateLimiter, uploadCsv, importProductsCsv);
router.post('/products/bulk-price-adjust', restrictToPermission('product:write'), adminActionRateLimiter, validateBody(bulkProductPriceAdjustSchema), bulkAdjustProductPrices);
router.get('/products/:id/versions', restrictToPermission('product:read'), validateParams(idParamsSchema), validateQuery(productVersionsQuerySchema), listProductVersions);
router.post('/products/:id/versions/:versionId/restore', restrictToPermission('product:write'), adminActionRateLimiter, validateParams(productVersionParamsSchema), restoreProductVersion);
router.patch('/products/:id', restrictToPermission('product:write'), adminActionRateLimiter, validateParams(idParamsSchema), validateBody(updateProductSchema), updateProduct);
router.delete('/products/:id', restrictToPermission('product:delete'), adminActionRateLimiter, validateParams(idParamsSchema), deleteProduct);
router.delete('/products/:id/permanent', restrictToPermission('product:delete'), adminActionRateLimiter, validateParams(idParamsSchema), permanentlyDeleteProduct);
router.get('/brands', restrictToPermission('brand:read'), validateQuery(brandListQuerySchema), listAdminBrands);
router.get('/brands/:id', restrictToPermission('brand:read'), validateParams(brandIdParamsSchema), getAdminBrand);
router.post('/brands', restrictToPermission('brand:write'), adminActionRateLimiter, validateBody(brandSchema), createBrand);
router.post('/brands/logo', restrictToPermission('brand:write'), uploadRateLimiter, uploadBrandLogo, uploadBrandLogoAsset);
router.patch('/brands/:id', restrictToPermission('brand:write'), adminActionRateLimiter, validateParams(brandIdParamsSchema), validateBody(brandSchema.partial()), updateBrand);
router.delete('/brands/:id', restrictToPermission('brand:delete'), adminActionRateLimiter, validateParams(brandIdParamsSchema), deleteBrand);
router.get('/categories', restrictToPermission('category:read'), listCategories);
router.post('/categories', restrictToPermission('category:write'), adminActionRateLimiter, validateBody(categorySchema), createCategory);
router.post('/categories/image', restrictToPermission('category:write'), uploadRateLimiter, uploadCategoryImage, uploadCategoryImageAsset);
router.patch('/categories/:id', restrictToPermission('category:write'), adminActionRateLimiter, validateParams(idParamsSchema), validateBody(categorySchema.partial()), updateCategory);
router.delete('/categories/:id', restrictToPermission('category:delete'), adminActionRateLimiter, validateParams(idParamsSchema), deleteCategory);
router.delete('/categories/:id/permanent', restrictToPermission('category:delete'), adminActionRateLimiter, validateParams(idParamsSchema), permanentlyDeleteCategory);
router.get('/product-questions', restrictToPermission('product:read'), validateQuery(adminProductQuestionQuerySchema), listProductQuestions);
router.patch('/product-questions/:id/answer', restrictToPermission('product:write'), adminActionRateLimiter, validateParams(idParamsSchema), validateBody(adminProductQuestionAnswerSchema), answerProductQuestion);
router.get('/reviews', restrictToPermission('product:read'), listReviews);
router.patch('/reviews/:id', restrictToPermission('product:write'), adminActionRateLimiter, validateParams(idParamsSchema), validateBody(reviewModerationSchema), moderateReview);
router.patch('/reviews/:id/reply', restrictToPermission('product:write'), adminActionRateLimiter, validateParams(idParamsSchema), validateBody(reviewReplySchema), replyToReview);
export default router;
